// src/services/mesasService.ts

// ============================================================================
// TIPOS E INTERFACES
// ============================================================================

export interface Mesa {
  id: number;
  numero: number;
  estado: 'LIBRE' | 'OCUPADA' | 'RESERVADA';
  capacidad?: number;
  ubicacion?: string;
  fechaCreacion?: string;
  fechaActualizacion?: string;
}

export interface MesaCreateRequest {
  numero: number;
  estado?: 'LIBRE' | 'OCUPADA' | 'RESERVADA';
  capacidad?: number;
  ubicacion?: string;
}

export interface MesaUpdateRequest extends Partial<MesaCreateRequest> {}

export interface ApiResponse<T> {
  success: boolean;
  data: T;
  message?: string;
  error?: string;
}

// ============================================================================
// CONFIGURACIÓN DE LA API
// ============================================================================

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8080/api';

class ApiError extends Error {
  constructor(public status: number, message: string) {
    super(message);
    this.name = 'ApiError';
  }
}

// ============================================================================
// FUNCIONES HELPER PARA REQUESTS
// ============================================================================

async function apiRequest<T>(
  endpoint: string, 
  options: RequestInit = {}
): Promise<T> {
  const url = `${API_BASE_URL}${endpoint}`;
  
  const defaultHeaders = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  const config: RequestInit = {
    ...options,
    headers: { ...defaultHeaders, ...options.headers },
  };

  try {
    const response = await fetch(url, config);
    
    if (!response.ok) {
      throw new ApiError(response.status, `HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    return data;
  } catch (error) {
    console.error('API Request Error:', error);
    throw error;
  }
}

// ============================================================================
// SERVICIOS DE MESAS
// ============================================================================

/**
 * Obtiene todas las mesas desde la base de datos
 */
export async function getMesas(): Promise<Mesa[]> {
  try {
    const response = await apiRequest<Mesa[]>('/mesas');
    return response;
  } catch (error) {
    console.error('Error al obtener mesas:', error);
    throw new Error('No se pudieron cargar las mesas');
  }
}

/**
 * Obtiene una mesa específica por ID
 */
export async function getMesaPorId(id: number): Promise<Mesa> {
  try {
    const response = await apiRequest<Mesa>(`/mesas/${id}`);
    return response;
  } catch (error) {
    console.error(`Error al obtener mesa ${id}:`, error);
    throw new Error(`No se pudo cargar la mesa con ID ${id}`);
  }
}

/**
 * Crea una nueva mesa en la base de datos
 */
export async function agregarMesa(mesa: MesaCreateRequest): Promise<Mesa> {
  try {
    // Validaciones básicas
    if (!mesa.numero || mesa.numero <= 0) {
      throw new Error('El número de mesa debe ser mayor a 0');
    }

    const response = await apiRequest<Mesa>('/mesas', {
      method: 'POST',
      body: JSON.stringify({
        numero: mesa.numero,
        estado: mesa.estado || 'LIBRE',
        capacidad: mesa.capacidad || 4,
        ubicacion: mesa.ubicacion || 'Salón principal'
      }),
    });

    return response;
  } catch (error) {
    console.error('Error al agregar mesa:', error);
    if (error instanceof ApiError && error.status === 409) {
      throw new Error('Ya existe una mesa con ese número');
    }
    throw new Error('No se pudo crear la mesa');
  }
}

/**
 * Actualiza una mesa existente
 */
export async function editarMesa(id: number, mesa: MesaUpdateRequest): Promise<Mesa> {
  try {
    if (!id || id <= 0) {
      throw new Error('ID de mesa inválido');
    }

    const response = await apiRequest<Mesa>(`/mesas/${id}`, {
      method: 'PUT',
      body: JSON.stringify(mesa),
    });

    return response;
  } catch (error) {
    console.error(`Error al editar mesa ${id}:`, error);
    if (error instanceof ApiError && error.status === 404) {
      throw new Error('Mesa no encontrada');
    }
    throw new Error('No se pudo actualizar la mesa');
  }
}

/**
 * Elimina una mesa de la base de datos
 */
export async function eliminarMesa(id: number): Promise<void> {
  try {
    if (!id || id <= 0) {
      throw new Error('ID de mesa inválido');
    }

    await apiRequest<void>(`/mesas/${id}`, {
      method: 'DELETE',
    });
  } catch (error) {
    console.error(`Error al eliminar mesa ${id}:`, error);
    if (error instanceof ApiError && error.status === 404) {
      throw new Error('Mesa no encontrada');
    }
    throw new Error('No se pudo eliminar la mesa');
  }
}

/**
 * Cambia el estado de una mesa
 */
export async function cambiarEstadoMesa(
  id: number, 
  nuevoEstado: Mesa['estado']
): Promise<Mesa> {
  try {
    return await editarMesa(id, { estado: nuevoEstado });
  } catch (error) {
    console.error(`Error al cambiar estado de mesa ${id}:`, error);
    throw new Error('No se pudo cambiar el estado de la mesa');
  }
}

/**
 * Obtiene mesas filtradas por estado
 */
export async function getMesasPorEstado(estado: Mesa['estado']): Promise<Mesa[]> {
  try {
    const response = await apiRequest<Mesa[]>(`/mesas?estado=${estado}`);
    return response;
  } catch (error) {
    console.error(`Error al obtener mesas con estado ${estado}:`, error);
    throw new Error(`No se pudieron cargar las mesas ${estado.toLowerCase()}s`);
  }
}

/**
 * Verifica si el servicio de mesas está disponible
 */
export async function verificarConexion(): Promise<boolean> {
  try {
    await apiRequest<any>('/mesas/health');
    return true;
  } catch (error) {
    console.warn('Servicio de mesas no disponible:', error);
    return false;
  }
}

// ============================================================================
// FUNCIONES DE UTILIDAD
// ============================================================================

/**
 * Valida los datos de una mesa antes de enviarlos
 */
export function validarMesa(mesa: MesaCreateRequest): string[] {
  const errores: string[] = [];

  if (!mesa.numero || mesa.numero <= 0) {
    errores.push('El número de mesa debe ser mayor a 0');
  }

  if (mesa.capacidad && mesa.capacidad <= 0) {
    errores.push('La capacidad debe ser mayor a 0');
  }

  if (mesa.estado && !['LIBRE', 'OCUPADA', 'RESERVADA'].includes(mesa.estado)) {
    errores.push('Estado inválido');
  }

  return errores;
}

/**
 * Formatea el estado para mostrar
 */
export function formatearEstado(estado: Mesa['estado']): string {
  const estados = {
    'LIBRE': 'Libre',
    'OCUPADA': 'Ocupada',
    'RESERVADA': 'Reservada'
  };
  return estados[estado] || estado;
}

/**
 * Obtiene el color asociado al estado
 */
export function obtenerColorEstado(estado: Mesa['estado']): string {
  const colores = {
    'LIBRE': 'green',
    'OCUPADA': 'red',
    'RESERVADA': 'yellow'
  };
  return colores[estado] || 'gray';
}

// ============================================================================
// MOCK DATA PARA DESARROLLO (REMOVER EN PRODUCCIÓN)
// ============================================================================

const MOCK_MESAS: Mesa[] = [
  {
    id: 1,
    numero: 1,
    estado: 'LIBRE',
    capacidad: 4,
    ubicacion: 'Salón principal',
    fechaCreacion: new Date().toISOString(),
  },
  {
    id: 2,
    numero: 2,
    estado: 'OCUPADA',
    capacidad: 2,
    ubicacion: 'Terraza',
    fechaCreacion: new Date().toISOString(),
  },
  {
    id: 3,
    numero: 3,
    estado: 'RESERVADA',
    capacidad: 6,
    ubicacion: 'Salón VIP',
    fechaCreacion: new Date().toISOString(),
  },
];

/**
 * Función para usar datos mock cuando el backend no esté disponible
 */
export async function getMesasMock(): Promise<Mesa[]> {
  // Simular delay de red
  await new Promise(resolve => setTimeout(resolve, 500));
  return [...MOCK_MESAS];
}
